/**
 * Shared document inventory for district documents.
 * Reads from data/document-index.json (board-meeting-sourced PDFs)
 * and supplements with artifacts/documents/ (manually curated files).
 *
 * Source: document-index.json is generated by scripts that scrape
 * BoardDocs agendas and classify attachments by type/subtype.
 */

import { readFileSync, readdirSync } from 'fs';
import { resolve } from 'path';

const R2_BASE = 'https://data.rcsd.info';

/**
 * Load document inventory from document-index.json + artifacts/documents/.
 * @param {string} rootDir — project root directory
 * @returns {{ budget: Object, lcap: Object, spsa: Object, sarc: Object }}
 *   Each keyed by schoolYear, with arrays of { title, url, subtype, school? }
 */
// Charter schools supervised by RCSD but with separate budgets/LCAPs
const CHARTER_PATTERNS = /rocketship|kipp|connect\b/i;

function isCharterDoc(doc) {
  return CHARTER_PATTERNS.test(doc.title || '') ||
    (doc.schools?.length === 1 && doc.schools[0] === 'rocketship');
}

export function scanDocuments(rootDir) {
  const indexPath = resolve(rootDir, 'data/document-index.json');
  const index = JSON.parse(readFileSync(indexPath, 'utf-8'));

  // ---- Budget: group by schoolYear, then subtype ----
  // Exclude charter school budget docs (Rocketship, KIPP, Connect)
  const budget = {};
  for (const d of index.documents.filter(d => d.type === 'budget' && !isCharterDoc(d))) {
    const year = d.schoolYear || 'Other';
    if (!budget[year]) budget[year] = [];
    budget[year].push({
      title: prettyBudgetTitle(d),
      url: d.url,
      subtype: d.subtype,
      meetingDate: d.meetingDate,
    });
  }
  // Sort each year's docs by subtype priority then date
  const budgetOrder = ['adopted-budget', 'first-interim', 'second-interim',
    'unaudited-actuals', 'multi-year-projection', 'presentation',
    'gann-limit', 'developer-fee', 'budget-reduction'];
  for (const year of Object.keys(budget)) {
    budget[year].sort((a, b) => {
      const ai = budgetOrder.indexOf(a.subtype);
      const bi = budgetOrder.indexOf(b.subtype);
      if (ai !== bi) return (ai === -1 ? 99 : ai) - (bi === -1 ? 99 : bi);
      return (a.meetingDate || '').localeCompare(b.meetingDate || '');
    });
  }

  // ---- LCAP: group by schoolYear ----
  // Exclude charter school LCAPs
  const lcap = {};
  for (const d of index.documents.filter(d => d.type === 'lcap' && !isCharterDoc(d))) {
    const year = d.schoolYear || 'Other';
    if (!lcap[year]) lcap[year] = [];
    lcap[year].push({
      title: prettyLcapTitle(d),
      url: d.url,
      subtype: d.subtype,
      meetingDate: d.meetingDate,
    });
  }

  // ---- SPSA: group by schoolYear → school ----
  const spsa = {};
  for (const d of index.documents.filter(d => d.type === 'spsa')) {
    const year = d.schoolYear || 'Other';
    if (!spsa[year]) spsa[year] = [];
    // Each PDF belongs to schools[0] per agenda grouping
    const school = d.schools?.[0];
    if (!school) continue; // skip docs not tagged to a specific school
    // Skip if we already have a newer SPSA for this school+year (prefer latest meeting date)
    const existing = spsa[year].find(s => s.school === school);
    if (existing) {
      // Keep the one from the later meeting date
      if ((d.meetingDate || '') > (existing.meetingDate || '')) {
        Object.assign(existing, { url: d.url, meetingDate: d.meetingDate });
      }
      continue;
    }
    spsa[year].push({
      school,
      url: d.url,
      meetingDate: d.meetingDate,
    });
  }
  // Sort each year's schools alphabetically
  for (const year of Object.keys(spsa)) {
    spsa[year].sort((a, b) => a.school.localeCompare(b.school));
  }

  // ---- SARC: group by schoolYear → school ----
  // First load from document-index.json (board-presented SARCs)
  const sarc = {};
  for (const d of index.documents.filter(d => d.type === 'sarc')) {
    const year = d.schoolYear || 'Other';
    if (!sarc[year]) sarc[year] = { schools: [] };
    const school = d.schools?.[0];
    if (!school) continue;
    const existing = sarc[year].schools.find(s => s.school === school);
    if (existing) {
      if ((d.meetingDate || '') > (existing.meetingDate || '')) {
        Object.assign(existing, { url: d.url, meetingDate: d.meetingDate });
      }
      continue;
    }
    sarc[year].schools.push({
      school,
      url: d.url,
      meetingDate: d.meetingDate,
    });
  }
  // Supplement with artifacts/documents/sarc/ (has English/Spanish split)
  try {
    const sarcRoot = resolve(rootDir, 'artifacts/documents/sarc');
    for (const year of readdirSync(sarcRoot).sort()) {
      if (!sarc[year]) sarc[year] = { schools: [] };
      for (const lang of ['english', 'spanish']) {
        try {
          const langDir = resolve(sarcRoot, year, lang);
          for (const f of readdirSync(langDir).sort()) {
            if (!f.endsWith('.pdf')) continue;
            const school = f.replace('.pdf', '');
            const key = `${lang}_${school}`;
            // Store language-specific versions separately
            if (!sarc[year][key]) {
              sarc[year][key] = {
                school,
                lang,
                url: `${R2_BASE}/documents/sarc/${year}/${lang}/${f}`,
              };
            }
          }
        } catch {}
      }
    }
  } catch {}
  // Sort each year's schools
  for (const year of Object.keys(sarc)) {
    if (sarc[year].schools) {
      sarc[year].schools.sort((a, b) => a.school.localeCompare(b.school));
    }
  }

  return { budget, lcap, spsa, sarc };
}

// ---- Pretty-print helpers ----

const BUDGET_SUBTYPE_LABELS = {
  'adopted-budget': 'Adopted Budget',
  'first-interim': 'First Interim Report',
  'second-interim': 'Second Interim Report',
  'unaudited-actuals': 'Unaudited Actuals',
  'multi-year-projection': 'Multi-Year Projection',
  'presentation': 'Budget Presentation',
  'gann-limit': 'Gann Limit Resolution',
  'developer-fee': 'Developer Fee Study',
  'budget-reduction': 'Budget Reduction Plan',
};

function prettyBudgetTitle(doc) {
  const base = BUDGET_SUBTYPE_LABELS[doc.subtype] || doc.subtype;
  // Some subtypes have multiple docs per year (e.g. multiple presentations)
  // Use a short title suffix from the original to disambiguate
  const title = doc.title || '';
  // Extract useful suffixes like "MYP", "Letter", "Combined"
  if (doc.subtype === 'first-interim' || doc.subtype === 'second-interim') {
    if (/myp|multi.year/i.test(title)) return base + ' — MYP';
    if (/presentation/i.test(title)) return base + ' — Presentation';
    if (/letter|review/i.test(title)) return base + ' — Review Letter';
    if (/connect/i.test(title)) return base + ' — Connect Report';
  }
  if (doc.subtype === 'adopted-budget') {
    if (/myp|multi.year/i.test(title)) return 'Adopted Budget — MYP';
    if (/presentation/i.test(title)) return 'Adopted Budget — Presentation';
    if (/resolution/i.test(title)) return 'Adopted Budget — Resolution';
    if (/summary/i.test(title)) return 'Adopted Budget — Summary';
    if (/connect/i.test(title)) return 'Adopted Budget — Connect Report';
  }
  if (doc.subtype === 'unaudited-actuals') {
    if (/presentation/i.test(title)) return 'Unaudited Actuals — Presentation';
    if (/connect/i.test(title)) return 'Unaudited Actuals — Connect Report';
  }
  return base;
}

function prettyLcapTitle(doc) {
  const title = doc.title || '';
  if (doc.subtype === 'mid-year') {
    if (/budget/i.test(title)) return 'LCAP Mid-Year Budget Report';
    return 'LCAP Mid-Year Report';
  }
  // Annual LCAPs
  if (/budget.*overview.*parent/i.test(title)) return 'LCAP Budget Overview for Parents';
  if (/federal.*addendum/i.test(title)) return 'LCAP Federal Addendum';
  if (/public.*hearing/i.test(title)) return 'LCAP Public Hearing Draft';
  if (/connect/i.test(title)) return 'LCAP Connect Report';
  if (/presentation/i.test(title)) return 'LCAP Presentation';
  if (/board.*approved|adopted/i.test(title)) return 'LCAP (Board Approved)';
  if (/combined/i.test(title)) return 'LCAP Combined';
  if (/annual.*update/i.test(title)) return 'LCAP Annual Update';
  return 'LCAP';
}

/**
 * Pretty-print a school slug (e.g. 'adelante-selby' → 'Adelante Selby').
 */
export function prettySchool(slug) {
  const map = {
    'adelante-selby': 'Adelante Selby',
    'clifford': 'Clifford',
    'garfield': 'Garfield',
    'henry-ford': 'Henry Ford',
    'hoover': 'Hoover',
    'kennedy': 'Kennedy',
    'mckinley-mit': 'McKinley MIT',
    'north-star': 'North Star',
    'orion': 'Orion',
    'roosevelt': 'Roosevelt',
    'roy-cloud': 'Roy Cloud',
    'taft': 'Taft',
  };
  return map[slug] || slug.split('-').map(w => w[0].toUpperCase() + w.slice(1)).join(' ');
}

/**
 * Pretty-print a document name slug, stripping year prefixes.
 */
export function prettyDocName(slug) {
  return slug
    .replace(/^\d{4}-\d{2}-/, '')  // strip year prefix
    .split('-').map(w => w[0].toUpperCase() + w.slice(1)).join(' ');
}

export { R2_BASE };
